query:
CREATE TABLE `online_sessions` (
	`id` varchar(64) NOT NULL,
	`playerId` int NOT NULL,
	`userId` int,
	`deviceId` varchar(64),
	`sessionId` varchar(64) NOT NULL,
	`status` enum('active','paused','idle') NOT NULL DEFAULT 'active',
	`lastHeartbeat` timestamp NOT NULL DEFAULT (now()),
	`startedAt` timestamp NOT NULL DEFAULT (now()),
	`createdAt` timestamp NOT NULL DEFAULT (now()),
	CONSTRAINT `online_sessions_id` PRIMARY KEY(`id`)
);
CREATE TABLE `players` (
	`id` int AUTO_INCREMENT NOT NULL,
	`userId` int,
	`deviceId` varchar(64),
	`name` varchar(255) NOT NULL,
	`email` varchar(320),
	`type` enum('registered','anonymous') NOT NULL,
	`isPremium` int NOT NULL DEFAULT 0,
	`totalPuzzles` int NOT NULL DEFAULT 0,
	`totalCorrect` int NOT NULL DEFAULT 0,
	`totalTimeMs` int NOT NULL DEFAULT 0,
	`completedCycles` int NOT NULL DEFAULT 0,
	`accuracy` decimal(5,2) DEFAULT '0',
	`rating` int NOT NULL DEFAULT 1200,
	`lastActivityAt` timestamp NOT NULL DEFAULT (now()),
	`createdAt` timestamp NOT NULL DEFAULT (now()),
	`updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP,
	CONSTRAINT `players_id` PRIMARY KEY(`id`)
);
CREATE INDEX `idx_online_playerId` ON `online_sessions` (`playerId`);
CREATE INDEX `idx_online_userId` ON `online_sessions` (`userId`);
CREATE INDEX `idx_online_deviceId` ON `online_sessions` (`deviceId`);
CREATE INDEX `idx_online_lastHeartbeat` ON `online_sessions` (`lastHeartbeat`);
CREATE INDEX `idx_online_status` ON `online_sessions` (`status`);
CREATE INDEX `idx_players_userId` ON `players` (`userId`);
CREATE INDEX `idx_players_deviceId` ON `players` (`deviceId`);
CREATE INDEX `idx_players_type` ON `players` (`type`);
CREATE INDEX `idx_players_lastActivity` ON `players` (`lastActivityAt`);

